    "hero.eyebrow": "Ancient wisdom · Scientific foundation",
    "hero.title": "Discover the healing power of nature",
    "hero.sub": "Herbal recipes rooted in thousands of years of tradition, backed by modern science. Teas, oil blends, and healing herbs — all natural, all evidence-based.",
    "hero.cta1": "Explore recipes",
    "hero.cta2": "Sources",
    "disclaimer": "This site does not constitute medical advice. If you have a chronic condition or take medication, consult your doctor.",

    "section.tea.tag": "Herbal Teas",
    "section.tea.title": "Ancient teas for modern life",
    "section.tea.desc": "A tea tradition spanning thousands of years — from Hippocrates and Chinese medicine to Anatolian healing plants and modern phytotherapy.",

    "section.oils.tag": "Oil Blends",
    "section.oils.title": "The power of natural oils",
    "section.oils.desc": "In ancient Egyptian, Greek, and Anatolian medicine, oils served as medicine, cosmetic, and food all at once.",

    "section.herbs.tag": "Healing Herbs Encyclopedia",
    "section.herbs.title": "The essence of ancient wisdom",
    "section.herbs.desc": "Herbs that have traveled from antiquity to the present, studied by clinicians and supported by scientific evidence.",

    "section.tips.tag": "Important Notes",
    "section.tips.title": "Using herbs correctly",

    "section.sources.tag": "Sources & References",
    "section.sources.title": "Scientific and traditional sources",
    "section.sources.desc": "The information shared on this site is based on the following sources.",

    "badge.ancient": "Ancient",
    "badge.clinical": "Clinical evidence",
    "badge.meta": "Meta-analysis",
    "badge.rct": "RCT evidence",
    "badge.systematic": "Systematic review",
    "badge.randomized": "Randomized trial",
